    /** @var array<string, string> */
    private const VIEWBOXES = [
        'gallery-pin' => '0 0 10 13',
        'gallery-arrow' => '0 0 14 14',
        'gallery-empty' => '0 0 48 48',
    ];

    /** @var array<string, string> */
    private const SYMBOL_FILLS = [
        'gallery-arrow' => 'none',
        'gallery-empty' => 'none',
    ];

    public static function normalize(string $name): string
    {
        return str_starts_with($name, 'bi-') ? substr($name, 3) : $name;
    }

    /** @return array<string, string> */
    public static function icons(): array
    {
        return self::PATHS;
    }

    public static function resolveKey(string $name): string
    {
        $key = self::normalize($name);

        return isset(self::PATHS[$key]) ? $key : 'box';
    }

    /** @return array<string, string> */
    public static function spriteIcons(): array
    {
        return self::PATHS;
    }

    public static function has(string $name): bool
    {
        return isset(self::PATHS[self::normalize($name)]);
    }

    public static function viewBox(string $name): string
    {
        $key = self::normalize($name);

        return self::VIEWBOXES[$key] ?? '0 0 16 16';
    }

    public static function symbolFill(string $name): string
    {
        $key = self::normalize($name);

        return self::SYMBOL_FILLS[$key] ?? 'currentColor';
    }

    public static function paths(string $name): ?string
    {
        $key = self::normalize($name);

        return self::PATHS[$key] ?? self::PATHS['box'] ?? null;
    }
}